function updateViewportDimensions() {
    var t = window
      , e = document
      , i = e.documentElement
      , e = e.getElementsByTagName("body")[0];
    return {
        width: t.innerWidth || i.clientWidth || e.clientWidth,
        height: t.innerHeight || i.clientHeight || e.clientHeight
    }
}
var viewport = updateViewportDimensions()
  , waitForFinalEvent = function() {
    var n = {};
    return function(t, e, i) {
        n[i = i || "Don't call this twice without a uniqueId"] && clearTimeout(n[i]),
        n[i] = setTimeout(t, e)
    }
}()
  , timeToWaitForLast = 100;
function loadGravatars() {
    768 <= (viewport = updateViewportDimensions()).width && jQuery(".comment img[data-gravatar]").each(function() {
        jQuery(this).attr("src", jQuery(this).attr("data-gravatar"))
    })
}
